ORDER BY c.blog_cate_id ASC ORDER BY c.blog_cate_id DESC ORDER BY c.blog_cate_nm ASC ORDER BY c.blog_cate_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
