site_id = #{siteId}, blog_cate_nm = #{blogCateNm}, parent_blog_cate_id = #{parentBlogCateId}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
